import{_ as o,H as t,f as a,i}from"./chunks/framework.DzzgwZ9Y.js";const m=JSON.parse('{"title":"Compatibility Scope (Cobra v1.x)","description":"","frontmatter":{},"headers":[],"relativePath":"reference/compat.md","filePath":"reference/compat.md"}'),l={name:"reference/compat.md"};function r(s,e,c,n,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="compatibility-scope-cobra-v1-x" tabindex="-1">Compatibility Scope (Cobra v1.x) <a class="header-anchor" href="#compatibility-scope-cobra-v1-x" aria-label="Permalink to &quot;Compatibility Scope (Cobra v1.x)&quot;">​</a></h1><p>This project defines &quot;Cobra parity&quot; as: given the same command tree + argv, Clasp should match Cobra v1.x&#39;s <strong>observable CLI behaviors</strong> (not copying the Go API surface).</p><h2 id="must-support-compatibility-contract" tabindex="-1">Must Support (Compatibility Contract) <a class="header-anchor" href="#must-support-compatibility-contract" aria-label="Permalink to &quot;Must Support (Compatibility Contract)&quot;">​</a></h2><p>These are &quot;compatibility commitments&quot;: behavioral changes should include corresponding examples + CTest.</p><ul><li>Command tree: subcommands, aliases, hidden/deprecated, groups, suggestions</li><li>Hooks: persistent + local (inheritance and ordering)</li><li>Args validators: NoArgs/Exact/Min/Max/Range</li><li>Flags: persistent vs local, required/hidden/deprecated, group constraints, repeated flags, NoOptDefVal</li><li>Parsing semantics: <code>--k=v</code>, <code>-k v</code>, <code>-k=v</code>, <code>-abc</code>, <code>-ovalue</code>, <code>--no-foo</code>, <code>NoOptDefVal</code>, <code>--</code></li><li>help/usage/version: <code>--help/-h</code>, <code>help [cmd]</code>, default values display, sorting toggles, examples</li><li>Completion: bash/zsh/fish/powershell + <code>__complete</code> candidates + directives</li><li>External source merging: <code>flag &gt; env &gt; config &gt; default</code></li></ul><h2 id="should-support-best-effort" tabindex="-1">Should Support (Best-Effort) <a class="header-anchor" href="#should-support-best-effort" aria-label="Permalink to &quot;Should Support (Best-Effort)&quot;">​</a></h2><p>These are important for &quot;Cobra-like feel&quot; but not strict contracts (unless locked by CTest):</p><ul><li>Byte-for-byte consistency with Cobra&#39;s default English text/whitespace</li><li>More unusual pflag edge cases (sorting, error text details, rare interactions)</li><li>Completion script details in shell/runtime (Clasp only outputs directives)</li></ul><h2 id="non-goals-explicitly-not-pursued" tabindex="-1">Non-Goals (Explicitly Not Pursued) <a class="header-anchor" href="#non-goals-explicitly-not-pursued" aria-label="Permalink to &quot;Non-Goals (Explicitly Not Pursued)&quot;">​</a></h2><ul><li>Go template language equivalence (Clasp only does placeholder replacement + complete override functions)</li><li>Copying the entire Cobra/pflag Go API surface (e.g., <code>*pflag.FlagSet</code>)</li><li>Full pflag type surface (can extend via <code>clasp::Value</code>)</li><li>Full Viper drop-in replacement</li></ul><h2 id="known-differences-currently-acceptable" tabindex="-1">Known Differences (Currently Acceptable) <a class="header-anchor" href="#known-differences-currently-acceptable" aria-label="Permalink to &quot;Known Differences (Currently Acceptable)&quot;">​</a></h2><ul><li>Template language capability limited (no conditions/loops/pipes/funcs)</li><li><code>--help/-h</code> and <code>--version</code> as built-in flags (even when not explicitly declared)</li><li>Built-in type surface is a subset (<code>bool/int/int64/uint64/float/double/duration/string</code> + helpers)</li><li>Completion details depend on shell/runtime</li><li>Error text not guaranteed byte-for-byte consistent (unless locked by CTest)</li></ul><h2 id="recommended-process-to-make-best-effort-into-contract" tabindex="-1">Recommended Process to Make Best-Effort Into Contract <a class="header-anchor" href="#recommended-process-to-make-best-effort-into-contract" aria-label="Permalink to &quot;Recommended Process to Make Best-Effort Into Contract&quot;">​</a></h2><ol><li>Add reproducer/examples in <code>examples/</code></li><li>Add CTest assertions in <code>CMakeLists.txt</code> (lock output/exit code/key semantics)</li><li>Implement behavior and ensure cross-platform consistency (macOS/Linux/Windows)</li></ol>',14)])])}const f=o(l,[["render",r]]);export{m as __pageData,f as default};
